package com.vycepay.admin.api.v1;
import java.util.*; import com.vycepay.admin.application.service.AdminReadService; import com.vycepay.common.api.*; import org.springframework.http.ResponseEntity; import org.springframework.web.bind.annotation.*;
/** Dashboard aggregate APIs for admin overview screens. */
@RestController @RequestMapping("/api/admin/v1/dashboard")
public class DashboardController{private final AdminReadService s; public DashboardController(AdminReadService s){this.s=s;} @GetMapping("/summary") public ResponseEntity<ApiSuccessResponse<Map<String,Object>>> summary(){return ResponseEntity.ok(ApiSuccessResponses.ok("DASHBOARD_SUMMARY","Dashboard summary",s.dashboardSummary()));} @GetMapping("/tx-volume-chart") public ResponseEntity<ApiSuccessResponse<List<Map<String,Object>>>> txVolume(@RequestParam(defaultValue="30") int days){return ResponseEntity.ok(ApiSuccessResponses.ok("DASHBOARD_TX_VOLUME","Transaction volume",s.txVolumeChart(days)));} @GetMapping("/tx-type-donut") public ResponseEntity<ApiSuccessResponse<Map<String,Object>>> txTypes(@RequestParam(defaultValue="30") int days){return ResponseEntity.ok(ApiSuccessResponses.ok("DASHBOARD_TX_TYPES","Transaction types",s.txTypeDonut(days)));} @GetMapping("/kyc-status-chart") public ResponseEntity<ApiSuccessResponse<List<Map<String,Object>>>> kyc(){return ResponseEntity.ok(ApiSuccessResponses.ok("DASHBOARD_KYC","KYC status",s.kycStatusChart()));} @GetMapping("/alerts") public ResponseEntity<ApiSuccessResponse<Map<String,Object>>> alerts(){return ResponseEntity.ok(ApiSuccessResponses.ok("DASHBOARD_ALERTS","Alerts",s.alerts()));} @GetMapping("/recent-transactions") public ResponseEntity<ApiSuccessResponse<List<Map<String,Object>>>> recent(@RequestParam(defaultValue="10") int limit){return ResponseEntity.ok(ApiSuccessResponses.ok("DASHBOARD_RECENT_TX","Recent transactions",s.recentTransactions(limit)));}}
